const body = $input.first().json?.body || $input.first().json;
const msg  = body?.data?.message || body?.message || body || {};
const phone = (msg?.key?.remoteJid || body?.phone || '').replace('@s.whatsapp.net','');
const text  = msg?.message?.conversation || msg?.message?.extendedTextMessage?.text || msg?.text || body?.text || '';
const type  = msg?.message?.imageMessage ? 'image' : msg?.message?.documentMessage ? 'document' : 'text';
const name  = msg?.pushName || body?.name || phone;
return [{ json:{ phone, text, type, name } }];

// Step: new
// Task: Show language menu. If user picks 1/2/3, save language, send PDPA, advance to pdpa.
const phone = $('Extract Message').item.json.phone;
const text  = ($('Extract Message').item.json.text || '').trim();

const FLASK   = 'http://127.0.0.1:5051';
const BAILEYS = 'http://127.0.0.1:3001';

async function send(msg)   { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`,         headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step, extra={}) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step, ...extra}), returnFullResponse:false }); }

const LANG_MENU = 'Hi! I\'m Ava 👋 Saya Ava!\n\nPlease choose your language / Sila pilih bahasa anda:\n\n1️⃣ Bahasa Malaysia\n2️⃣ English\n3️⃣ 中文';

const PDPA = {
  BM: 'Sebelum kita mulakan, sila ambil perhatian 📋\n\nAva Resume Studio mengumpul maklumat peribadi anda (nama, pendidikan, pengalaman kerja, kemahiran) semata-mata untuk tujuan penghasilan résumé. Maklumat anda tidak akan dikongsi dengan pihak ketiga.\n\n• Anda bertanggungjawab atas ketepatan maklumat yang diberikan.\n• Perkhidmatan kami tidak menjamin peluang pekerjaan.\n• Bayaran balik tidak tersedia setelah résumé dihantar.\n\nBalas "Setuju" untuk meneruskan. 😊',
  EN: 'Before we begin, please note 📋\n\nAva Resume Studio collects your personal information (name, education, work history, skills) solely for the purpose of creating your resume. Your data will not be shared with third parties.\n\n• You are responsible for the accuracy of information provided.\n• Our service does not guarantee employment outcomes.\n• Refunds are not available once the resume has been delivered.\n\nReply "Agree" to proceed. 😊',
  CN: '開始之前，請注意 📋\n\nAva Resume Studio 收集您的個人資料（姓名、學歷、工作經歷、技能），僅用於製作履歷。您的資料不會與第三方共享。\n\n• 您對所提供資料的準確性負責。\n• 本服務不保證求職結果。\n• 履歷交付後不提供退款。\n\n回覆「同意」即表示您接受以上條款。😊'
};

const langMap = { '1':'BM', '2':'EN', '3':'CN' };
const choice = langMap[text];

if (choice) {
  await setStep('pdpa', { chosen_language: choice });
  await saveMsg('user', text);
  await saveMsg('assistant', PDPA[choice]);
  await send(PDPA[choice]);
} else {
  await send(LANG_MENU);
}

return [{ json: { ok: true } }];

// Step: pdpa
// Task: Wait for agree. If agreed, show service menu, advance to service_select.
const phone = $('Extract Message').item.json.phone;
const text  = ($('Extract Message').item.json.text || '').trim();
const lang  = $('Get Session').item.json?.chosen_language || 'EN';

const FLASK   = 'http://127.0.0.1:5051';
const BAILEYS = 'http://127.0.0.1:3001';

async function send(msg)   { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`,         headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step}), returnFullResponse:false }); }

const isAgreed = /^(agree|setuju|同意|ok|yes|ya|是|對|好)$/i.test(text);

const SERVICE_MENU = {
  BM: 'Terima kasih! 😊\n\nSila pilih perkhidmatan:\n\n1️⃣ Tulis Resume dari Awal — RM7\n2️⃣ Perbaiki Resume Sedia Ada — RM5\n3️⃣ Pengoptimuman ATS — RM5\n4️⃣ Surat Lamaran — RM3\n5️⃣ Pakej Penuh (Resume + Surat Lamaran) — RM10\n\nBalas nombor pilihan anda.',
  EN: 'Thank you! 😊\n\nPlease choose a service:\n\n1️⃣ Write Resume from Scratch — RM7\n2️⃣ Improve Existing Resume — RM5\n3️⃣ ATS Optimisation — RM5\n4️⃣ Cover Letter — RM3\n5️⃣ Full Package (Resume + Cover Letter) — RM10\n\nReply with the number of your choice.',
  CN: '感謝您的同意！😊\n\n請選擇服務：\n\n1️⃣ 從頭撰寫履歷 — RM7\n2️⃣ 改善現有履歷 — RM5\n3️⃣ ATS 優化 — RM5\n4️⃣ 求職信 — RM3\n5️⃣ 全套（履歷 + 求職信）— RM10\n\n請回覆號碼。'
};

const REMINDER = {
  BM: 'Sila balas "Setuju" untuk meneruskan. 😊',
  EN: 'Please reply "Agree" to proceed. 😊',
  CN: '請回覆「同意」以繼續。😊'
};

await saveMsg('user', text);

if (isAgreed) {
  await setStep('service_select');
  await saveMsg('assistant', SERVICE_MENU[lang]);
  await send(SERVICE_MENU[lang]);
} else {
  await saveMsg('assistant', REMINDER[lang]);
  await send(REMINDER[lang]);
}

return [{ json: { ok: true } }];

// Step: service_select
// Task: User picks 1-5. Store service, advance to template_layout, send layout image.
const phone = $('Extract Message').item.json.phone;
const text  = ($('Extract Message').item.json.text || '').trim();
const lang  = $('Get Session').item.json?.chosen_language || 'EN';

const FLASK   = 'http://127.0.0.1:5051';
const BAILEYS = 'http://127.0.0.1:3001';

async function send(msg)   { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`,         headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function sendImg(imagePath) { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send-image`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, imagePath}), returnFullResponse:false }); }
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step}), returnFullResponse:false }); }
async function saveData(data) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/data`, headers:{'Content-Type':'application/json'}, body:JSON.stringify(data), returnFullResponse:false }); }

const SERVICES = {
  '1': { name_BM:'Tulis Resume dari Awal',      name_EN:'Write Resume from Scratch', name_CN:'從頭撰寫履歷', amount:7  },
  '2': { name_BM:'Perbaiki Resume Sedia Ada',    name_EN:'Improve Existing Resume',   name_CN:'改善現有履歷', amount:5  },
  '3': { name_BM:'Pengoptimuman ATS',             name_EN:'ATS Optimisation',          name_CN:'ATS 優化',    amount:5  },
  '4': { name_BM:'Surat Lamaran',                 name_EN:'Cover Letter',              name_CN:'求職信',       amount:3  },
  '5': { name_BM:'Pakej Penuh',                   name_EN:'Full Package',              name_CN:'全套',         amount:10 },
};

const LAYOUT_ASK = {
  BM: 'Pilihan hebat! 🎨\n\nSekarang sila pilih susun atur resume anda:\n\n*A* = Dua kolum (moden, padat)\n*B* = Satu kolum (klasik, mudah dibaca)\n\nBalas A atau B.',
  EN: 'Great choice! 🎨\n\nNow please choose your resume layout:\n\n*A* = Two-column (modern, compact)\n*B* = Single-column (classic, easy to read)\n\nReply A or B.',
  CN: '很好！🎨\n\n請選擇履歷版面：\n\n*A* = 雙欄（現代、緊湊）\n*B* = 單欄（經典、易讀）\n\n回覆 A 或 B。'
};

const RETRY = {
  BM: 'Sila pilih nombor 1 hingga 5 untuk memilih perkhidmatan. 😊',
  EN: 'Please reply with a number from 1 to 5 to choose a service. 😊',
  CN: '請回覆 1 至 5 的數字選擇服務。😊'
};

const choice = text.match(/^[1-5]$/)?.[0];
await saveMsg('user', text);

if (choice) {
  const svc = SERVICES[choice];
  const svcName = svc[`name_${lang}`];
  await saveData({ service: svcName, amount: svc.amount });
  await setStep('template_layout');
  await saveMsg('assistant', LAYOUT_ASK[lang]);
  await send(LAYOUT_ASK[lang]);
  await sendImg('${PROJECT_ROOT}/resume-ai/templates/layout_preview.png');
} else {
  await saveMsg('assistant', RETRY[lang]);
  await send(RETRY[lang]);
}

return [{ json: { ok: true } }];

// Step: template_select
// Show 6 template previews OR detect choice 1-6
const phone    = $('Extract Message').item.json.phone;
const text     = ($('Extract Message').item.json.text || '').trim();
const lang     = $('Get Session').item.json?.chosen_language || 'EN';
const session  = $('Get Session').item.json || {};
const existing = session.collected_data || {};

const FLASK   = 'http://127.0.0.1:5051';
const BAILEYS = 'http://127.0.0.1:3001';
const TPL_DIR = '${PROJECT_ROOT}/resume-ai/templates';

async function send(msg) { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function sendImg(imagePath, caption) {
  try { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send-image`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, imagePath, caption}), returnFullResponse:false }); }
  catch(e) { console.log('sendImg failed:', e.message); }
}
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step}), returnFullResponse:false }); }
async function saveData(data) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/data`, headers:{'Content-Type':'application/json'}, body:JSON.stringify(data), returnFullResponse:false }); }

const TEMPLATE_NAMES = {
  BM: ['Klasik','Moden','Minimal','Bold','Eksekutif','Fresh Grad'],
  EN: ['Classic','Modern','Minimal','Bold','Executive','Fresh Grad'],
  CN: ['經典','現代','簡約','大膽','高管','應屆生']
};

// Detect choice 1-6
const match = text.match(/\b([1-6])\b/);
const choice = match ? parseInt(match[1]) : null;

await saveMsg('user', text);

if (!existing._templates_shown) {
  // First time in this step — send all 6 previews
  const INTRO = {
    BM: '🎨 Pilih template resume anda!\n\nSila lihat 6 contoh di bawah dan balas dengan nombor pilihan anda (1-6):',
    EN: '🎨 Choose your resume template!\n\nHere are 6 designs — reply with your choice (1-6):',
    CN: '🎨 請選擇您的履歷模板！\n\n以下是 6 種設計——請回覆您的選擇（1-6）：'
  };
  await saveMsg('assistant', INTRO[lang]);
  await send(INTRO[lang]);

  // Send all 6 preview images
  const names = TEMPLATE_NAMES[lang];
  for (let i = 1; i <= 6; i++) {
    await sendImg(`${TPL_DIR}/preview_${i}.png`, `*${i}. ${names[i-1]}*`);
  }

  await saveData({ _templates_shown: true });

} else if (choice && choice >= 1 && choice <= 6) {
  // User made a choice
  const names = TEMPLATE_NAMES[lang];
  await saveData({ template_choice: choice });
  await setStep('collecting');

  const CONFIRM = {
    BM: `Template *${choice}. ${TEMPLATE_NAMES.BM[choice-1]}* dipilih ✅\n\n✏️ Sekarang sila berikan maklumat berikut:\n\n1️⃣ Nama penuh\n2️⃣ Nombor telefon & emel\n3️⃣ *Jawatan sasaran*\n4️⃣ Pengalaman kerja (syarikat, jawatan, tahun, tugas utama)\n5️⃣ Pendidikan (universiti, program, tahun, CGPA)\n6️⃣ Kemahiran utama\n\nBoleh hantar semua sekali atau satu per satu 😊`,
    EN: `Template *${choice}. ${TEMPLATE_NAMES.EN[choice-1]}* selected ✅\n\n✏️ Please provide the following information:\n\n1️⃣ Full name\n2️⃣ Phone number & email\n3️⃣ *Target job title*\n4️⃣ Work experience (company, role, year, key duties)\n5️⃣ Education (university, programme, year, CGPA)\n6️⃣ Key skills\n\nYou can send everything at once or one by one 😊`,
    CN: `已選模板 *${choice}. ${TEMPLATE_NAMES.CN[choice-1]}* ✅\n\n✏️ 請提供以下資料：\n\n1️⃣ 全名\n2️⃣ 電話號碼和電郵\n3️⃣ *目標職位*\n4️⃣ 工作經歷（公司、職位、年份、主要職責）\n5️⃣ 學歷（大學、科系、年份、GPA）\n6️⃣ 主要技能\n\n可一次發送或逐項提供 😊`
  };
  await saveMsg('assistant', CONFIRM[lang]);
  await send(CONFIRM[lang]);

} else {
  // Already shown but no valid choice yet
  const RE_ASK = {
    BM: 'Sila balas dengan nombor template pilihan anda (1-6) 😊',
    EN: 'Please reply with your template choice (1-6) 😊',
    CN: '請回覆您選擇的模板號碼（1-6）😊'
  };
  await saveMsg('assistant', RE_ASK[lang]);
  await send(RE_ASK[lang]);
}

return [{ json: { ok: true } }];

// Step: collecting
// AI task: extract resume data, merge with existing. When complete, create order.
const phone   = $('Extract Message').item.json.phone;
const text    = ($('Extract Message').item.json.text || '').trim();
const lang    = $('Get Session').item.json?.chosen_language || 'EN';
const session = $('Get Session').item.json || {};
const existing = session.collected_data || {};

const FLASK   = 'http://127.0.0.1:5051';
const BAILEYS = 'http://127.0.0.1:3001';
const GEMINI_KEY = 'YOUR_GEMINI_API_KEY';
const GROQ_KEY   = 'YOUR_GROQ_API_KEY';

async function send(msg)   { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`,         headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step}), returnFullResponse:false }); }
async function saveData(data) { return await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/data`, headers:{'Content-Type':'application/json'}, body:JSON.stringify(data), returnFullResponse:false }); }

const langName = { BM:'Bahasa Malaysia', EN:'English', CN:'Traditional Chinese' }[lang];

const systemPrompt = `You are Ava, a resume assistant collecting information to build a resume.
Reply language: ${langName}.
Previously collected data: ${JSON.stringify(existing)}

Extract any NEW resume information from the user's message and merge with existing data.
Required fields: name, target_job, experience_years, education, work_history, skills.
If any required field is still missing after merging, gently ask for it.
If ALL fields are present, show a confirmation summary and ask user to confirm.
The user confirms with: yes/ok/confirm/betul/setuju/是/好/對.

Output ONLY valid JSON:
{
  "reply": "your response in ${langName}",
  "extracted_data": { "name":"...", "target_job":"...", "experience_years":"...", "education":"...", "work_history":"...", "skills":"..." },
  "is_all_complete": false,
  "user_confirmed": false
}
Set is_all_complete=true only when ALL 6 fields are present.
Set user_confirmed=true only when user explicitly confirmed a summary.`;

const messages = [
  { role:'system', content: systemPrompt },
  { role:'user',   content: text }
];

let raw = '';
try {
  const r = await this.helpers.httpRequest({ method:'POST', url:'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions', headers:{Authorization:`Bearer ${GEMINI_KEY}`,'Content-Type':'application/json'}, body:JSON.stringify({model:'gemini-2.0-flash',temperature:0.2,response_format:{type:'json_object'},messages}), returnFullResponse:false });
  raw = r.choices?.[0]?.message?.content || '';
} catch(e) {
  try {
    const r = await this.helpers.httpRequest({ method:'POST', url:'https://api.groq.com/openai/v1/chat/completions', headers:{Authorization:`Bearer ${GROQ_KEY}`,'Content-Type':'application/json'}, body:JSON.stringify({model:'llama-3.3-70b-versatile',temperature:0.2,response_format:{type:'json_object'},messages}), returnFullResponse:false });
    raw = r.choices?.[0]?.message?.content || '';
  } catch(e2) { raw = '{"reply":"Please provide your information.","extracted_data":{},"is_all_complete":false,"user_confirmed":false}'; }
}

let parsed = { reply:'Please provide your information.', extracted_data:{}, is_all_complete:false, user_confirmed:false };
try { parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || raw); } catch(e) {}

const reply         = parsed.reply || 'Please provide your information.';
const extractedData = parsed.extracted_data || {};
const isComplete    = parsed.is_all_complete === true;
const confirmed     = parsed.user_confirmed === true;

// Always save extracted data
if (Object.keys(extractedData).length > 0) {
  await saveData(extractedData);
}

await saveMsg('user', text);
await saveMsg('assistant', reply);
await send(reply);

// Only create order when complete AND confirmed
if (isComplete && confirmed) {
  const merged = { ...existing, ...extractedData };
  const orderResp = await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/orders`, headers:{'Content-Type':'application/json'},
    body: JSON.stringify({
      phone_number: phone,
      customer_name: merged.name || '',
      service: merged.service || 'Resume',
      amount: merged.amount || 7,
      details: { target_job: merged.target_job, layout: merged.layout, colour: merged.colour, style: merged.style }
    }), returnFullResponse:false });

  const ticket = orderResp.ticket_no || '';
  await setStep('payment_pending');

  const TICKET_MSG = {
    BM: `Pesanan anda telah diterima! 🎉\n\nNombor Pesanan: *${ticket}*\n\nSila buat pembayaran:\n🏦 Example Bank\n💳 Akaun: 0000000000\n👤 Nama: Example Account Name\n💰 Jumlah: RM${merged.amount || 7}\n\nGunakan nombor pesanan sebagai rujukan. Hantar screenshot selepas bayar. 😊`,
    EN: `Your order has been received! 🎉\n\nOrder Number: *${ticket}*\n\nPlease make payment:\n🏦 Example Bank\n💳 Account: 0000000000\n👤 Name: Example Account Name\n💰 Amount: RM${merged.amount || 7}\n\nUse the order number as reference. Send screenshot after payment. 😊`,
    CN: `您的訂單已收到！🎉\n\n訂單號碼：*${ticket}*\n\n請完成付款：\n🏦 Example Bank\n💳 帳號：0000000000\n👤 姓名：Example Account Name\n💰 金額：RM${merged.amount || 7}\n\n請以訂單號碼作為付款備注。付款後發送截圖。😊`
  };
  await saveMsg('assistant', TICKET_MSG[lang]);
  await send(TICKET_MSG[lang]);
}

return [{ json: { ok: true } }];

// Step: payment_pending
// Task: Detect payment proof (image or keywords). Notify Telegram, advance to feedback.
const phone   = $('Extract Message').item.json.phone;
const text    = ($('Extract Message').item.json.text || '').trim();
const msgType = $('Extract Message').item.json.type || 'text';
const lang    = $('Get Session').item.json?.chosen_language || 'EN';
const name    = $('Extract Message').item.json.name || phone;

const FLASK    = 'http://127.0.0.1:5051';
const BAILEYS  = 'http://127.0.0.1:3001';
const TG_TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';
const TELEGRAM_ADMIN_CHAT_ID = YOUR_TELEGRAM_ADMIN_CHAT_ID;

async function send(msg)   { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`,         headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step}), returnFullResponse:false }); }

// Detect payment proof: image attachment OR payment keywords
const isImage    = msgType === 'image' || msgType === 'document';
const hasKeyword = /paid|bayar|dah bayar|已付|transfer|slip|receipt|payment/i.test(text);
const isPaid     = isImage || hasKeyword;

await saveMsg('user', text || '[payment proof]');

if (isPaid) {
  // Notify Telegram
  const tgMsg = `💰 Payment Received!\n\nFrom: ${phone}\nName: ${name}\n\nPlease verify payment and deliver resume.`;
  try {
    await this.helpers.httpRequest({ method:'POST', url:`https://api.telegram.org/bot${TG_TOKEN}/sendMessage`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({chat_id:TG_CHAT, text:tgMsg}), returnFullResponse:false });
  } catch(e) { console.log('TG notify failed:', e.message); }

  await setStep('feedback');

  const THANKS = {
    BM: 'Terima kasih! 🙏 Pembayaran anda sedang disahkan. Resume anda akan siap dalam 24 jam.\n\nSambil menunggu, boleh beri kami penilaian?\n\n⭐ Beri markah 1-5 untuk perkhidmatan kami.',
    EN: 'Thank you! 🙏 Your payment is being verified. Your resume will be ready within 24 hours.\n\nWhile waiting, could you rate our service?\n\n⭐ Give us a rating from 1 to 5.',
    CN: '謝謝！🙏 您的付款正在核實中。您的履歷將在 24 小時內完成。\n\n趁此機會，能給我們評分嗎？\n\n⭐ 請給我們 1 到 5 分的評價。'
  };
  await saveMsg('assistant', THANKS[lang]);
  await send(THANKS[lang]);
} else {
  const REMIND = {
    BM: 'Sila hantar bukti pembayaran (screenshot) setelah melakukan pembayaran. 😊',
    EN: 'Please send your payment screenshot after completing the transfer. 😊',
    CN: '請在完成匯款後，發送付款截圖。😊'
  };
  await saveMsg('assistant', REMIND[lang]);
  await send(REMIND[lang]);
}

return [{ json: { ok: true } }];

// Step: feedback
// AI task: collect rating (1-5) and comment. Save, send farewell, set done.
const phone   = $('Extract Message').item.json.phone;
const text    = ($('Extract Message').item.json.text || '').trim();
const lang    = $('Get Session').item.json?.chosen_language || 'EN';
const session = $('Get Session').item.json || {};

const FLASK   = 'http://127.0.0.1:5051';
const BAILEYS = 'http://127.0.0.1:3001';
const GEMINI_KEY = 'YOUR_GEMINI_API_KEY';
const GROQ_KEY   = 'YOUR_GROQ_API_KEY';

async function send(msg)   { await this.helpers.httpRequest({ method:'POST', url:`${BAILEYS}/send`,         headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone, text:msg}), returnFullResponse:false }); }
async function saveMsg(role, content) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/conversations`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({phone_number:phone, role, content}), returnFullResponse:false }); }
async function setStep(step) { await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/step`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({current_step:step}), returnFullResponse:false }); }

const langName = { BM:'Bahasa Malaysia', EN:'English', CN:'Traditional Chinese' }[lang];
const existingData = session.collected_data || {};

const systemPrompt = `You are Ava. The customer just received their resume. Collect feedback.
Reply language: ${langName}.
Previously collected: rating=${existingData._feedback_rating || 'none'}, comment=${existingData._feedback_comment || 'none'}.
Step 1: If no rating yet, extract a star rating (1-5) from the message.
Step 2: If rating exists but no comment, ask for a short comment.
Step 3: If both exist, thank them warmly and say goodbye.
Output ONLY valid JSON:
{"reply":"your response","rating":null or 1-5,"comment":null or "string","is_done":false}
Set is_done=true only when BOTH rating and comment are present.`;

const messages = [
  { role:'system', content: systemPrompt },
  { role:'user',   content: text }
];

let raw = '';
try {
  const r = await this.helpers.httpRequest({ method:'POST', url:'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions', headers:{Authorization:`Bearer ${GEMINI_KEY}`,'Content-Type':'application/json'}, body:JSON.stringify({model:'gemini-2.0-flash',temperature:0.2,response_format:{type:'json_object'},messages}), returnFullResponse:false });
  raw = r.choices?.[0]?.message?.content || '';
} catch(e) {
  try {
    const r = await this.helpers.httpRequest({ method:'POST', url:'https://api.groq.com/openai/v1/chat/completions', headers:{Authorization:`Bearer ${GROQ_KEY}`,'Content-Type':'application/json'}, body:JSON.stringify({model:'llama-3.3-70b-versatile',temperature:0.2,response_format:{type:'json_object'},messages}), returnFullResponse:false });
    raw = r.choices?.[0]?.message?.content || '';
  } catch(e2) { raw = '{"reply":"Thank you for your feedback!","rating":null,"comment":null,"is_done":false}'; }
}

let parsed = { reply:'Thank you!', rating:null, comment:null, is_done:false };
try { parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || raw); } catch(e) {}

const reply  = parsed.reply || 'Thank you!';
const isDone = parsed.is_done === true;

await saveMsg('user', text);
await saveMsg('assistant', reply);
await send(reply);

// Save partial feedback data
const feedbackUpdate = {};
if (parsed.rating)  feedbackUpdate._feedback_rating  = parsed.rating;
if (parsed.comment) feedbackUpdate._feedback_comment = parsed.comment;
if (Object.keys(feedbackUpdate).length > 0) {
  await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/session/${phone}/data`, headers:{'Content-Type':'application/json'}, body:JSON.stringify(feedbackUpdate), returnFullResponse:false });
}

if (isDone) {
  const rating  = parsed.rating  || existingData._feedback_rating  || 0;
  const comment = parsed.comment || existingData._feedback_comment || '';

  // Get latest order for ticket_no
  let ticketNo = '';
  try {
    const orders = await this.helpers.httpRequest({ method:'GET', url:`${FLASK}/orders/${phone}`, returnFullResponse:false });
    if (Array.isArray(orders) && orders.length > 0) ticketNo = orders[0].ticket_no || '';
  } catch(e) {}

  // Save feedback to DB
  await this.helpers.httpRequest({ method:'POST', url:`${FLASK}/feedback`, headers:{'Content-Type':'application/json'},
    body: JSON.stringify({ phone_number:phone, ticket_no:ticketNo, rating, comment }), returnFullResponse:false });

  await setStep('done');
}

return [{ json: { ok: true } }];
